"use client";

import { motion, AnimatePresence } from "framer-motion";
import {
  ArrowLeft,
  CheckCircle,
  Clock,
  XCircle,
  Car,
  FileText,
  Landmark,
  ShieldCheck,
} from "lucide-react";
import axios from "axios";
import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";

/* ================= PAGE ================= */

export default function AdminVendorReviewPage() {
  const { id } = useParams();
  const router = useRouter();

  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [showApprove, setShowApprove] = useState(false);
  const [showReject, setShowReject] = useState(false);
  const [rejectReason, setRejectReason] = useState("");
  const [actionLoading, setActionLoading] = useState(false);

  useEffect(() => {
    async function load() {
      const res = await axios.get(`/api/admin/vendors/${id}`);
      setData(res.data.vendor);
      setLoading(false);
    }
    load();
  }, [id]);

  const approveVendor = async () => {
    setActionLoading(true);
    await axios.post(`/api/admin/vendors/${id}/approve`);
    router.push("/admin/dashboard");
  };

  const rejectVendor = async () => {
    if (!rejectReason.trim()) return;
    setActionLoading(true);
    await axios.post(`/api/admin/vendors/${id}/reject`, {
      reason: rejectReason,
    });
    router.push("/admin/dashboard");
  };

  if (loading)
    return (
      <div className="min-h-screen grid place-items-center text-gray-500">
        Loading vendor review…
      </div>
    );

  if (!data) return null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-100 to-gray-200">

      {/* ================= HEADER ================= */}
      <header className="sticky top-0 z-40 backdrop-blur-xl bg-white/70 border-b">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center gap-4">
          <button
            onClick={() => router.back()}
            className="w-10 h-10 rounded-full border flex items-center justify-center hover:bg-gray-100 transition"
          >
            <ArrowLeft size={18} />
          </button>

          <div className="flex-1">
            <p className="font-semibold text-lg">{data.name}</p>
            <p className="text-xs text-gray-500">{data.email}</p>
          </div>

          <StatusBadge status={data.vendorStatus} />
        </div>
      </header>

      {/* ================= MAIN ================= */}
      <main className="max-w-7xl mx-auto px-4 py-12 grid lg:grid-cols-3 gap-10">

        {/* LEFT SIDE */}
        <div className="lg:col-span-2 space-y-8">

          <AnimatedCard title="Vehicle Details" icon={<Car size={18} />}>
            <InfoRow label="Vehicle Type" value={data.vehicle?.type} />
            <InfoRow label="Registration Number" value={data.vehicle?.number} />
            <InfoRow label="Model" value={data.vehicle?.model} />
          </AnimatedCard>

          <AnimatedCard title="Documents" icon={<FileText size={18} />}>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
              <DocPreview label="Aadhaar" url={data.documents?.aadhaarUrl} />
              <DocPreview label="License" url={data.documents?.licenseUrl} />
              <DocPreview label="RC" url={data.documents?.rcUrl} />
            </div>
          </AnimatedCard>

        </div>

        {/* RIGHT SIDE */}
        <div className="space-y-8">

          <AnimatedCard title="Bank Details" icon={<Landmark size={18} />}>
            <InfoRow label="Account Holder" value={data.bank?.accountHolderName} />
            <InfoRow label="IFSC Code" value={data.bank?.ifsc} />
            <InfoRow label="UPI ID" value={data.bank?.upi || "—"} />
          </AnimatedCard>

          {data.vendorStatus === "pending" && (
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              className="bg-white rounded-[32px] p-8 shadow-xl space-y-6"
            >
              <div className="flex items-center gap-2 font-semibold">
                <ShieldCheck size={18} />
                Admin Decision
              </div>

              <p className="text-sm text-gray-500">
                Verify documents carefully before approving.
              </p>

              <div className="flex flex-col gap-4">
                <button
                  onClick={() => setShowApprove(true)}
                  className="py-3 rounded-2xl bg-gradient-to-r from-black to-gray-800 text-white font-semibold hover:opacity-90 transition"
                >
                  Approve Vendor
                </button>

                <button
                  onClick={() => setShowReject(true)}
                  className="py-3 rounded-2xl border font-semibold hover:bg-gray-100 transition"
                >
                  Reject Vendor
                </button>
              </div>
            </motion.div>
          )}
        </div>
      </main>

      {/* APPROVE MODAL */}
      <ConfirmModal
        open={showApprove}
        title="Approve Vendor?"
        description="Confirm all information has been verified."
        confirmText="Yes, Approve"
        loading={actionLoading}
        onClose={() => setShowApprove(false)}
        onConfirm={approveVendor}
      />

      {/* REJECT MODAL */}
      <RejectModal
        open={showReject}
        reason={rejectReason}
        setReason={setRejectReason}
        loading={actionLoading}
        onClose={() => setShowReject(false)}
        onConfirm={rejectVendor}
      />
    </div>
  );
}

/* ================= REUSABLE UI ================= */

function AnimatedCard({ title, icon, children }: any) {
  return (
    <motion.div
      whileHover={{ y: -4 }}
      className="bg-white rounded-[32px] p-8 shadow-xl space-y-6"
    >
      <div className="flex items-center gap-2 font-semibold">
        {icon}
        {title}
      </div>
      {children}
    </motion.div>
  );
}

function DocPreview({ label, url }: any) {
  const isImage = url?.match(/\.(jpg|jpeg|png|webp)$/i);
  const isPdf = url?.endsWith(".pdf");

  return (
    <div className="bg-gray-50 rounded-2xl border overflow-hidden shadow-sm">
      <div className="px-4 py-2 border-b text-sm font-semibold">
        {label}
      </div>

      <div className="h-52 flex items-center justify-center bg-white">
        {!url && <span className="text-xs text-gray-400">Not uploaded</span>}

        {isImage && (
          <img src={url} className="w-full h-full object-cover" />
        )}

        {isPdf && <iframe src={url} className="w-full h-full" />}
      </div>

      {url && (
        <a
          href={url}
          target="_blank"
          className="block text-center text-xs py-2 font-medium hover:bg-gray-100"
        >
          Open full document
        </a>
      )}
    </div>
  );
}

function ConfirmModal({ open, title, description, confirmText, loading, onClose, onConfirm }: any) {
  return (
    <AnimatePresence>
      {open && (
        <motion.div
          className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center px-4"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
        >
          <motion.div
            initial={{ scale: 0.9 }}
            animate={{ scale: 1 }}
            className="bg-white rounded-3xl p-6 w-full max-w-sm"
          >
            <h2 className="text-lg font-bold">{title}</h2>
            <p className="text-sm text-gray-500 mt-2">{description}</p>

            <div className="flex gap-3 mt-6">
              <button onClick={onClose} className="flex-1 py-2 rounded-xl border">
                Cancel
              </button>
              <button
                onClick={onConfirm}
                disabled={loading}
                className="flex-1 py-2 rounded-xl bg-black text-white"
              >
                {confirmText}
              </button>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

function RejectModal({ open, reason, setReason, loading, onClose, onConfirm }: any) {
  return (
    <ConfirmModal
      open={open}
      title="Reject Vendor"
      description={
        <textarea
          placeholder="Enter rejection reason (required)"
          value={reason}
          onChange={(e) => setReason(e.target.value)}
          className="w-full mt-3 border rounded-xl p-3 text-sm"
        />
      }
      confirmText="Reject"
      loading={loading}
      onClose={onClose}
      onConfirm={onConfirm}
    />
  );
}

function InfoRow({ label, value }: any) {
  return (
    <div className="flex justify-between text-sm">
      <span className="text-gray-500">{label}</span>
      <span className="font-semibold">{value || "—"}</span>
    </div>
  );
}

function StatusBadge({ status }: any) {
  if (status === "approved")
    return <Badge text="Approved" icon={<CheckCircle size={14} />} className="bg-green-100 text-green-700" />;
  if (status === "rejected")
    return <Badge text="Rejected" icon={<XCircle size={14} />} className="bg-red-100 text-red-700" />;
  return <Badge text="Pending" icon={<Clock size={14} />} className="bg-yellow-100 text-yellow-700" />;
}

function Badge({ text, icon, className }: any) {
  return (
    <span className={`px-4 py-2 rounded-full text-xs font-semibold inline-flex items-center gap-2 ${className}`}>
      {icon}
      {text}
    </span>
  );
}

import { NextResponse } from "next/server";
import { auth } from "@/auth";
import connectDb from "@/lib/db";

import User from "@/models/user.model";
import Vehicle from "@/models/vehicle.model";

/* ================================
   GET → ADMIN DASHBOARD DATA
================================ */

export async function GET() {
  try {
    /* ---------- AUTH ---------- */
    const session = await auth();
    if (!session?.user?.id || session.user.role !== "admin") {
      return NextResponse.json(
        { message: "Unauthorized" },
        { status: 401 }
      );
    }

    await connectDb();

    /* ================================
       STATS
    ================================ */

    const totalVendors = await User.countDocuments({
      role: "vendor",
    });

    const approved = await User.countDocuments({
      role: "vendor",
      vendorStatus: "approved",
    });

    const pending = await User.countDocuments({
      role: "vendor",
      vendorStatus: "pending",
    });

    const rejected = await User.countDocuments({
      role: "vendor",
      vendorStatus: "rejected",
    });

    /* ================================
       PENDING VENDOR REVIEWS
       (Vendor onboarding verification)
    ================================ */

    const pendingVendorUsers = await User.find({
      role: "vendor",
      vendorStatus: "pending",
    })
      .select("name email")
      .lean();

    const vendorIds = pendingVendorUsers.map((v) => v._id);

    const vendorVehicles = await Vehicle.find({
      owner: { $in: vendorIds },
    })
      .select("owner type")
      .lean();

    const vehicleTypeMap = new Map(
      vendorVehicles.map((v) => [
        String(v.owner),
        v.type,
      ])
    );

    const pendingVendors = pendingVendorUsers.map((v) => ({
      _id: v._id,
      name: v.name,
      email: v.email,
      vehicleType:
        vehicleTypeMap.get(String(v._id)) || "—",
    }));

    /* ================================
       PENDING VEHICLE PRICING REVIEWS
       (Pricing + image approval)
    ================================ */

    const pendingVehiclesRaw = await Vehicle.find({
      status: "pending",
      baseFare: { $exists: true },
      pricePerKm: { $exists: true },
    })
      .populate({
        path: "owner",
        select: "name email",
      })
      .lean();

    const pendingVehicles = pendingVehiclesRaw.map(
      (v: any) => ({
        _id: v._id,
        ownerName: v.owner?.name,
        ownerEmail: v.owner?.email,
        vehicleType: v.type,
        baseFare: v.baseFare,
        pricePerKm: v.pricePerKm,
      })
    );

    /* ================================
       RESPONSE
    ================================ */

    return NextResponse.json({
      success: true,
      stats: {
        totalVendors,
        approved,
        pending,
        rejected,
      },
      pendingVendors,
      pendingVehicles,
    });
  } catch (error) {
    console.error("ADMIN DASHBOARD ERROR:", error);
    return NextResponse.json(
      { message: "Server error" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { auth } from "@/auth";
import connectDB from "@/lib/db";
import User from "@/models/user.model";

export async function PATCH(req: Request) {
  try {
    const session = await auth();

    if (!session?.user?.id || session.user.role !== "admin") {
      return NextResponse.json(
        { message: "Unauthorized" },
        { status: 401 }
      );
    }

    const { roomId, action, reason } = await req.json();

    if (!roomId) {
      return NextResponse.json(
        { message: "Room ID required" },
        { status: 400 }
      );
    }

    if (!["approve", "reject"].includes(action)) {
      return NextResponse.json(
        { message: "Invalid action" },
        { status: 400 }
      );
    }

    await connectDB();

    const vendor = await User.findOne({
      videoKycRoomId: roomId,
      role: "vendor",
    });

    if (!vendor) {
      return NextResponse.json(
        { message: "Vendor not found" },
        { status: 404 }
      );
    }

    if (action === "approve") {
      vendor.videoKycStatus = "approved";
      vendor.videoKycRejectionReason = undefined;

      if (vendor.vendorOnboardingStep < 5) {
        vendor.vendorOnboardingStep = 5;
      }
    }

    if (action === "reject") {
      if (!reason || !reason.trim()) {
        return NextResponse.json(
          { message: "Rejection reason required" },
          { status: 400 }
        );
      }

      vendor.videoKycStatus = "rejected";
      vendor.videoKycRejectionReason = reason.trim();
    }

    await vendor.save();

    return NextResponse.json({
      success: true,
      status: vendor.videoKycStatus,
    });
  } catch (error: any) {
    return NextResponse.json(
      { message: error.message },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import mongoose from "mongoose";
import User from "@/models/user.model";
import connectDb from "@/lib/db";
import { sendMail } from "@/lib/mailer";
; // 👈 DB connection helper

/* ---------------- POST: REGISTER ---------------- */

export async function POST(req: NextRequest) {
  try {
    await connectDb();

    const body = await req.json();
    const { name, email, password } = body;

    /* ---------- VALIDATION ---------- */

    if (!name || !email || !password) {
      return NextResponse.json(
        { message: "All fields are required" },
        { status: 400 }
      );
    }

    if (password.length < 6) {
      return NextResponse.json(
        { message: "Password must be at least 6 characters" },
        { status: 400 }
      );
    }

    /* ---------- CHECK EXISTING USER ---------- */

    const existingUser = await User.findOne({ email });

    if (existingUser && existingUser.isEmailVerified) {
      return NextResponse.json(
        { message: "User already exists. Please login." },
        { status: 409 }
      );
    }

    /* ---------- HASH PASSWORD ---------- */

    const hashedPassword = await bcrypt.hash(password, 10);

    /* ---------- GENERATE OTP ---------- */

    const otp = Math.floor(100000 + Math.random() * 900000).toString(); // 6-digit
    const otpExpiresAt = new Date(Date.now() + 10 * 60 * 1000); // 10 minutes

    /* ---------- CREATE / UPDATE USER ---------- */

    if (existingUser && !existingUser.isEmailVerified) {
      // Update OTP for unverified user
      existingUser.name = name;
      existingUser.password = hashedPassword;
      existingUser.otp = otp;
      existingUser.otpExpiresAt = otpExpiresAt;

      await existingUser.save();
    } else {
      await User.create({
        name,
        email,
        password: hashedPassword,
        role: "user",
        isEmailVerified: false,
        otp,
        otpExpiresAt,
      });
    }

    /* ---------- SEND OTP (PLACEHOLDER) ---------- */
    // 🔥 Replace with real email service (Nodemailer / Resend / AWS SES)
    console.log(`OTP for ${email}: ${otp}`);
    await sendMail(
       email,
        "Your OTP for Email Verification",
        `<h2>Your Email Verification OTP is <strong>${otp}</strong></h2>`
    )

    return NextResponse.json(
      {
        message: "OTP sent to email. Please verify.",
      },
      { status: 201 }
    );
  } catch (error: any) {
    console.error("REGISTER ERROR:", error);

    return NextResponse.json(
      { message: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import mongoose from "mongoose";
import User from "@/models/user.model";
import connectDb from "@/lib/db";

/* ---------------- POST: VERIFY OTP ---------------- */

export async function POST(req: NextRequest) {
  try {
    await connectDb();

    const body = await req.json();
    const { email, otp } = body;
console.log(otp)
    /* ---------- VALIDATION ---------- */

    if (!email || !otp) {
      return NextResponse.json(
        { message: "Email and OTP are required" },
        { status: 400 }
      );
    }

    /* ---------- FIND USER ---------- */

    const user = await User.findOne({ email });

    if (!user) {
      return NextResponse.json(
        { message: "User not found" },
        { status: 404 }
      );
    }

    /* ---------- ALREADY VERIFIED ---------- */

    if (user.isEmailVerified) {
      return NextResponse.json(
        { message: "Email already verified. Please login." },
        { status: 400 }
      );
    }

    /* ---------- OTP MATCH ---------- */

    if (!user.otp || user.otp !== otp) {
      return NextResponse.json(
        { message: "Invalid OTP" },
        { status: 401 }
      );
    }

    /* ---------- OTP EXPIRY ---------- */

    if (!user.otpExpiresAt || user.otpExpiresAt < new Date()) {
      return NextResponse.json(
        { message: "OTP expired. Please request a new one." },
        { status: 410 }
      );
    }

    /* ---------- VERIFY USER ---------- */

    user.isEmailVerified = true;
    user.otp = undefined;
    user.otpExpiresAt = undefined;

    await user.save();

    /* ---------- SUCCESS ---------- */

    return NextResponse.json(
      {
        message: "Email verified successfully",
        user: {
          id: user._id,
          name: user.name,
          email: user.email,
          role: user.role,
        },
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("VERIFY OTP ERROR:", error);

    return NextResponse.json(
      { message: "Internal server error" },
      { status: 500 }
    );
  }
}

