                    {dropResults.length > 0 && (
                      <motion.div
                        initial={{ opacity: 0, y: -4, scale: 0.98 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: -4, scale: 0.98 }}
                        transition={{ duration: 0.2 }}
                        className="absolute left-0 right-0 top-full mt-1 bg-white border border-zinc-200 rounded-2xl shadow-xl max-h-52 overflow-y-auto z-50"
                      >
                        {dropResults.map((p, i) => (
                          <motion.button
                            key={p.id}
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: i * 0.03 }}
                            onClick={() => {
                              setDrop(fmt(p));
                              setDropLat(p.lat); setDropLng(p.lng);
                              setDropResults([]);
                            }}
                            className="flex items-center gap-3 w-full px-4 py-3 text-left hover:bg-zinc-50 transition-colors border-b border-zinc-100 last:border-0"
                          >
                            <Navigation size={13} className="text-zinc-400 flex-shrink-0" />
                            <span className="text-sm text-zinc-800 font-medium truncate">{fmt(p)}</span>
                            <ChevronRight size={13} className="text-zinc-300 flex-shrink-0 ml-auto" />
                          </motion.button>
                        ))}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              </div>
            </motion.div>

            {/* ══ CTA ══ */}
            <motion.div
              variants={stepVariants} initial="hidden" animate="visible" transition={{ delay: 0.3 }}
            >
              <motion.button
                whileTap={{ scale: 0.97 }}
                whileHover={canContinue ? { scale: 1.02 } : {}}
                disabled={!canContinue}
                onClick={() => router.push(
                  `/search?pickup=${encodeURIComponent(pickup)}&drop=${encodeURIComponent(drop)}&vehicle=${vehicle}&mobileNumber=${encodeURIComponent(mobile)}&pickupLat=${pickupLat}&pickupLng=${pickupLng}&dropLat=${dropLat}&dropLng=${dropLng}`
                )}
                className="w-full h-14 rounded-2xl bg-zinc-900 hover:bg-black disabled:opacity-35 text-white font-black text-sm tracking-wide flex items-center justify-center gap-2.5 transition-colors shadow-lg disabled:shadow-none"
              >
                <span>Continue</span>
                <motion.div
                  animate={canContinue ? { x: [0, 4, 0] } : {}}
                  transition={{ duration: 1.2, repeat: Infinity, repeatDelay: 1 }}
                >
                  <ArrowRight size={17} />
                </motion.div>
              </motion.button>

              {/* Completion hint */}
              <AnimatePresence>
                {!canContinue && (
                  <motion.p
                    initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                    className="text-center text-zinc-400 text-[10px] font-medium mt-2.5 tracking-wide"
                  >
                    {!vehicle ? "Select a vehicle to continue" :
                     mobile.length < 10 ? "Enter a valid mobile number" :
                     !pickup ? "Enter pickup location" :
                     !drop ? "Enter drop location" : ""}
                  </motion.p>
                )}
              </AnimatePresence>
            </motion.div>

          </div>
        </div>

        {/* Bottom hint */}
        <motion.p
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.5 }}
          className="text-center text-zinc-400 text-[10px] mt-4 tracking-wide"
        >
          Rides are subject to driver availability
        </motion.p>

      </motion.div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import {
  IndianRupee,
  Loader2,
  Car,
  Calendar,
  ChevronRight,
  MapPin,
  Phone,
} from "lucide-react";
import axios from "axios";

interface Booking {
  _id: string;
  pickupAddress: string;
  dropAddress: string;
  fare: number;
  status: string;
  paymentStatus: string;
  paymentMethod?: string;
  createdAt: string;
  userMobileNumber?: string;
  driverMobileNumber?: string;
  vehicle?: {
    vehicleModel: string;
    imageUrl?: string;
  };
  driver?: {
    name: string;
  };
}

export default function MyBookingsPage() {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState("All");

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const res = await axios.get("/api/user/bookings");
      
        setBookings(res.data.bookings || []);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, []);

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      confirmed: "bg-emerald-50 text-emerald-700 border-emerald-200",
      completed: "bg-teal-50 text-teal-700 border-teal-200",
      requested: "bg-amber-50 text-amber-700 border-amber-200",
      awaiting_payment: "bg-blue-50 text-blue-700 border-blue-200",
      cancelled: "bg-rose-50 text-rose-700 border-rose-200",
      rejected: "bg-red-50 text-red-700 border-red-200",
      expired: "bg-gray-50 text-gray-700 border-gray-200",
    };
    return colors[status] || "bg-gray-50 text-gray-700 border-gray-200";
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      day: 'numeric',
      month: 'short',
      hour: '2-digit',
      minute: '2-digit'
    }).replace(',', '');
  };

  const filteredBookings = statusFilter === "All" 
    ? bookings 
    : bookings.filter(b => b.status === statusFilter.toLowerCase());

  return (
    <div className="min-h-screen bg-gray-50">
      
      {/* HEADER - CENTERED CONTENT */}
      <div className="bg-white border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="max-w-3xl mx-auto py-6">
            <h1 className="text-2xl font-semibold text-gray-900">My Bookings</h1>
            <p className="text-gray-500 text-sm mt-1">
              {bookings.length} {bookings.length === 1 ? 'ride' : 'rides'} found
            </p>
          </div>
        </div>
      </div>

      {/* MAIN CONTENT - CENTERED CARDS */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <div className="max-w-3xl mx-auto">
          
          {/* FILTER BAR */}
          <div className="flex justify-between items-center mb-6">
            <div className="text-sm text-gray-500">
              Showing {filteredBookings.length} bookings
            </div>
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="bg-white border border-gray-200 rounded-lg px-3 py-1.5 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option>All</option>
              <option>Confirmed</option>
              <option>Completed</option>
              <option>Requested</option>
              <option>Cancelled</option>
            </select>
          </div>

          {/* LOADING STATE */}
          {loading && (
            <div className="flex justify-center py-16">
              <Loader2 className="animate-spin w-8 h-8 text-blue-600" />
            </div>
          )}

          {/* EMPTY STATE */}
          {!loading && filteredBookings.length === 0 && (
            <div className="bg-white rounded-xl shadow-sm p-12 text-center">
              <Car className="w-12 h-12 text-gray-300 mx-auto mb-3" />
              <h3 className="text-lg font-medium text-gray-900">No bookings found</h3>
              <p className="text-gray-500 text-sm mt-1">Ready for a ride? Book one now!</p>
              <button className="mt-4 bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700">
                Book a Ride
              </button>
            </div>
          )}

          {/* BOOKINGS LIST */}
          {!loading && filteredBookings.length > 0 && (
            <div className="space-y-4">
              {filteredBookings.map((booking, index) => (
                <motion.div
                  key={booking._id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                >
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all overflow-hidden">
                    
                    {/* VEHICLE INFO WITH IMAGE */}
                    <div className="flex items-center gap-3 p-4 bg-gray-50 border-b border-gray-200">
                      {/* VEHICLE IMAGE */}
                      <div className="w-16 h-16 rounded-lg overflow-hidden bg-gray-200 flex-shrink-0 border border-gray-300">
                        {booking.vehicle?.imageUrl ? (
                          <img 
                            src={booking.vehicle.imageUrl} 
                            alt={booking.vehicle.vehicleModel}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center bg-gray-300">
                            <Car className="w-8 h-8 text-gray-500" />
                          </div>
                        )}
                      </div>
                      
                      {/* VEHICLE DETAILS */}
                      <div className="flex-1">
                        <div className="flex items-center justify-between">
                          <h3 className="font-semibold text-gray-900">
                            {booking.vehicle?.vehicleModel || "Standard Vehicle"}
                          </h3>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(booking.status)}`}>
                            {booking.status.replace("_", " ")}
                          </span>
                        </div>
                        <p className="text-sm text-gray-500 mt-1">
                          {booking.driver?.name ? `Driver: ${booking.driver.name}` : 'Driver assigning...'}
                        </p>
                      </div>
                    </div>

                    {/* ADDRESS SECTION - CLEARLY LABELED */}
                    <div className="p-4 space-y-3">
                      {/* PICKUP - GREEN */}
                      <div className="flex items-start gap-3">
                        <div className="flex-shrink-0 w-6 h-6 bg-green-100 rounded-full flex items-center justify-center">
                          <MapPin className="w-3 h-3 text-green-600" />
                        </div>
                        <div className="flex-1">
                          <span className="text-xs font-medium text-green-600 uppercase tracking-wider">PICKUP</span>
                          <p className="text-sm text-gray-700 mt-0.5 leading-relaxed">
                            {booking.pickupAddress}
                          </p>
                        </div>
                      </div>

                      {/* DROP - RED */}
                      <div className="flex items-start gap-3">
                        <div className="flex-shrink-0 w-6 h-6 bg-red-100 rounded-full flex items-center justify-center">
                          <MapPin className="w-3 h-3 text-red-600" />
                        </div>
                        <div className="flex-1">
                          <span className="text-xs font-medium text-red-600 uppercase tracking-wider">DROP</span>
                          <p className="text-sm text-gray-700 mt-0.5 leading-relaxed">
                            {booking.dropAddress}
                          </p>
                        </div>
                      </div>

                      {/* CONTACT NUMBERS SECTION */}
                      <div className="pt-3 mt-2 border-t border-gray-100 space-y-2">
                        {/* USER MOBILE NUMBER */}
                        {booking.userMobileNumber && (
                          <div className="flex items-start gap-3">
                            <div className="flex-shrink-0 w-6 h-6 bg-blue-100 rounded-full flex items-center justify-center">
                              <Phone className="w-3 h-3 text-blue-600" />
                            </div>
                            <div className="flex-1">
                              <span className="text-xs font-medium text-blue-600 uppercase tracking-wider">YOUR NUMBER</span>
                              <p className="text-sm text-gray-700 mt-0.5">
                                {booking.userMobileNumber}
                              </p>
                            </div>
                          </div>
                        )}

                        {/* DRIVER MOBILE NUMBER */}
                        {booking.driverMobileNumber && (
                          <div className="flex items-start gap-3">
                            <div className="flex-shrink-0 w-6 h-6 bg-purple-100 rounded-full flex items-center justify-center">
                              <Phone className="w-3 h-3 text-purple-600" />
                            </div>
                            <div className="flex-1">
                              <span className="text-xs font-medium text-purple-600 uppercase tracking-wider">DRIVER CONTACT</span>
                              <p className="text-sm text-gray-700 mt-0.5">
                                {booking.driverMobileNumber}
                              </p>
                            </div>
                          </div>
                        )}
                      </div>
                    </div>

                    {/* DATE AND FARE */}
                    <div className="flex items-center justify-between px-4 py-3 bg-gray-50 border-t border-gray-200">
                      <div className="flex items-center gap-2 text-sm text-gray-600">
                        <Calendar className="w-4 h-4 text-gray-400" />
                        <span>{formatDate(booking.createdAt)}</span>
                      </div>
                      <div className="flex items-center gap-1 font-semibold text-gray-900">
                        <IndianRupee className="w-4 h-4" />
                        <span>₹{booking.fare}</span>
                      </div>
                    </div>

                    {/* PAYMENT AND ACTION */}
                    <div className="flex items-center justify-between px-4 py-3 border-t border-gray-200">
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-500">Payment:</span>
                        
                        <span className={`text-xs px-2 py-1 rounded-full ${
                          booking.paymentStatus === 'paid' 
                            ? 'bg-green-100 text-green-700' 
                            : 'bg-yellow-100 text-yellow-700'
                        }`}>
                          {booking.paymentStatus || 'pending'}
                        </span>
                      </div>
                      <button
                        onClick={() => window.location.href = `/ride/${booking._id}`}
                        className="flex items-center gap-1 text-sm font-medium text-blue-600 hover:text-blue-700 bg-blue-50 hover:bg-blue-100 px-4 py-1.5 rounded-lg transition-colors"
                      >
                        <span>View Details</span>
                        <ChevronRight className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import {
  MapPin, Navigation, ShieldCheck,
  Bike, Car, Truck, Loader2, CheckCircle2,
  XCircle, Clock, CreditCard, Banknote,
  ArrowRight, RotateCcw, AlertCircle, Wallet,
} from "lucide-react";
import { useState, useEffect } from "react";
import { useSearchParams } from "next/navigation";
import { getSocket } from "@/lib/socket";

const VEHICLE_ICONS: Record<string, any> = {
  bike: Bike, auto: Car, car: Car, loading: Truck, truck: Truck,
};

type Status =
  | "idle" | "requested" | "awaiting_payment"
  | "rejected" | "expired" | "cancelled"
  | "payment" | "confirmed";

export default function CheckoutPage() {
  const params = useSearchParams();

  const pickup    = params.get("pickup")    || "Pickup Location";
  const drop      = params.get("drop")      || "Drop Location";
  const vehicle   = params.get("vehicle")   || "car";
  const vehicleId = params.get("vehicleId");
  const fare      = Number(params.get("fare")) || 249;
  const mobileNumber = params.get("mobileNumber") || "";
  const driverId  = params.get("driverId");
  const pickupLat = Number(params.get("pickupLat"));
  const pickupLng = Number(params.get("pickupLng"));
  const dropLat   = Number(params.get("dropLat"));
  const dropLng   = Number(params.get("dropLng"));

  const VehicleIcon = VEHICLE_ICONS[vehicle.toLowerCase()] || Car;

  const [loading,       setLoading]       = useState(false);
  const [bookingId,     setBookingId]     = useState<string | null>(null);
  const [status,        setStatus]        = useState<Status>("idle");
  const [paymentMethod, setPaymentMethod] = useState<"cash" | "online" | null>(null);

  /* ── CREATE BOOKING ── */
  const handleCreateBooking = async () => {
    try {
      setLoading(true);
      const res  = await fetch("/api/booking/create", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          vehicleId, driverId,
          pickupAddress: pickup, dropAddress: drop,
          pickupLocation: { type: "Point", coordinates: [pickupLng, pickupLat] },
          dropLocation:   { type: "Point", coordinates: [dropLng,   dropLat]   },
          fare, mobileNumber,
        }),
      });
      const data = await res.json();
      if (data.success) { setBookingId(data.booking._id); setStatus("requested"); }
      else alert(data.message || "Booking failed");
    } catch { alert("Something went wrong"); }
    finally { setLoading(false); }
  };

  function loadRazorpayScript() {
  return new Promise((resolve) => {

    if (typeof window === "undefined") {
      resolve(false);
      return;
    }

    if ((window as any).Razorpay) {
      resolve(true);
      return;
    }

    const script = document.createElement("script");
    script.src = "https://checkout.razorpay.com/v1/checkout.js";
    script.onload = () => resolve(true);
    script.onerror = () => resolve(false);

    document.body.appendChild(script);
  });
}

  /* ── PAYMENT CONFIRM ── */
 const handlePaymentConfirm = async () => {

  if (!bookingId || !paymentMethod) return;

  setLoading(true);

  try {

    if (paymentMethod === "cash") {

      const res = await fetch(`/api/booking/${bookingId}/confirm-payment`, {
        method:"POST",
        headers:{ "Content-Type":"application/json" },
        body:JSON.stringify({ method:"cash" })
      });

      const data = await res.json();

      if(data.success){
        window.location.href = `/ride/${bookingId}`;
      }

      return;
    }

    /* LOAD RAZORPAY SCRIPT */

    const razorpayLoaded = await loadRazorpayScript();

    if (!razorpayLoaded) {
      alert("Razorpay SDK failed to load");
      return;
    }

    /* CREATE ORDER */

    const orderRes = await fetch("/api/payment/create",{
      method:"POST",
      headers:{ "Content-Type":"application/json" },
      body:JSON.stringify({ bookingId })
    });

    const orderData = await orderRes.json();

    const options = {
      key: process.env.NEXT_PUBLIC_RAZORPAY_KEY,
      amount: orderData.amount,
      currency: "INR",
      name: "RYDEX",
      description: "Ride Payment",
      order_id: orderData.orderId,

      handler: async function (response:any) {

        const verify = await fetch("/api/payment/verify",{
          method:"POST",
          headers:{ "Content-Type":"application/json" },
          body:JSON.stringify({
            bookingId,
            ...response
          })
        });

        const verifyData = await verify.json();

        if(verifyData.success){
          window.location.href = `/ride/${bookingId}`;
        }

      }
    };

    const paymentObject = new (window as any).Razorpay(options);
    paymentObject.open();

  }

  catch(err){
    console.error(err);
    alert("Payment failed");
  }

  finally{
    setLoading(false);
  }
};

  /* ── CANCEL ── */
  const handleCancelBooking = async () => {
    if (!bookingId) return;
    await fetch(`/api/booking/${bookingId}/cancel`, { method: "POST" });
    setStatus("cancelled");
  };

  /* ── SOCKET ── */
  useEffect(() => {
    const socket = getSocket();
    socket.on("booking-updated", (data) => {
      if (data.status === "awaiting_payment") setStatus("awaiting_payment");
      if (data.status === "rejected")         setStatus("rejected");
      if (data.status === "confirmed")        setStatus("confirmed");
    });
    return () => { socket.off("booking-updated"); };
  }, []);

  /* ── RESTORE ── */
  useEffect(() => {
    (async () => {
      const res  = await fetch("/api/booking/my-active");
      const data = await res.json();
      if (data.booking) { setBookingId(data.booking._id); setStatus(data.booking.status); }
    })();
  }, []);

  /* ── awaiting_payment → payment after 2s ── */
  useEffect(() => {
    if (status !== "awaiting_payment") return;
    const t = setTimeout(() => setStatus("payment"), 2000);
    return () => clearTimeout(t);
  }, [status]);

  /* ── label ── */
  const vehicleLabel = vehicle.charAt(0).toUpperCase() + vehicle.slice(1);

  return (
    <div className="min-h-screen bg-zinc-100 px-4 py-12">

      {/* subtle dot grid */}
      <div className="fixed inset-0 pointer-events-none"
        style={{ backgroundImage: "radial-gradient(circle, #d4d4d8 1px, transparent 1px)", backgroundSize: "28px 28px", opacity: 0.45 }}
      />

      <div className="relative max-w-6xl mx-auto z-10">

        {/* ── PAGE HEADER ── */}
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
          className="mb-10"
        >
          <div className="flex items-center gap-2 mb-2">
            <div className="h-px w-8 bg-zinc-900" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400">Booking</span>
          </div>
          <h1 className="text-4xl font-black tracking-tight text-zinc-900">Checkout</h1>
          <p className="text-zinc-400 text-sm mt-1.5 font-medium">Review your ride and confirm</p>
        </motion.div>

        {/* ── GRID ── */}
        <div className="grid lg:grid-cols-2 gap-6">

          {/* ══ LEFT — RIDE DETAILS ══ */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.08, duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
            className="bg-white rounded-3xl border border-zinc-200 overflow-hidden shadow-[0_4px_24px_rgba(0,0,0,0.07)]"
          >
            {/* Top bar */}
            <div className="h-1 bg-zinc-900" />

            <div className="p-8 sm:p-10">
              {/* Vehicle row */}
              <div className="flex items-center justify-between mb-8">
                <div>
                  <p className="text-[10px] font-black uppercase tracking-[0.18em] text-zinc-400 mb-1">Selected Vehicle</p>
                  <h2 className="text-3xl font-black tracking-tight text-zinc-900">{vehicleLabel}</h2>
                </div>
                <div className="w-16 h-16 bg-zinc-900 rounded-2xl flex items-center justify-center shadow-lg">
                  <VehicleIcon size={28} className="text-white" />
                </div>
              </div>

              {/* Route */}
              <div className="bg-zinc-50 border border-zinc-100 rounded-2xl overflow-hidden mb-8">
                <div className="flex gap-4 px-5 py-4 border-b border-zinc-100">
                  <div className="flex flex-col items-center flex-shrink-0 pt-0.5">
                    <div className="w-3 h-3 rounded-full bg-zinc-900 border-2 border-white ring-1 ring-zinc-300" />
                    <div className="w-px flex-1 bg-zinc-300 my-1" style={{ minHeight: 12 }} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-[9px] font-black uppercase tracking-[0.18em] text-zinc-400 mb-0.5">Pickup</p>
                    <p className="text-sm font-semibold text-zinc-900 leading-snug truncate">{pickup}</p>
                  </div>
                  <MapPin size={14} className="text-zinc-400 flex-shrink-0 mt-1" />
                </div>
                <div className="flex gap-4 px-5 py-4">
                  <div className="flex-shrink-0 pt-0.5">
                    <div className="w-3 h-3 rounded-sm bg-zinc-900 border-2 border-white ring-1 ring-zinc-300" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-[9px] font-black uppercase tracking-[0.18em] text-zinc-400 mb-0.5">Drop</p>
                    <p className="text-sm font-semibold text-zinc-900 leading-snug truncate">{drop}</p>
                  </div>
                  <Navigation size={14} className="text-zinc-400 flex-shrink-0 mt-1" />
                </div>
              </div>

              {/* Fare */}
              <div className="flex items-end justify-between pt-6 border-t border-zinc-100">
                <div>
                  <p className="text-[10px] font-black uppercase tracking-[0.18em] text-zinc-400 mb-1">Total Fare</p>
                  <p className="text-zinc-400 text-xs font-medium">Includes base + distance charges</p>
                </div>
                <motion.div
                  initial={{ scale: 0.8, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  transition={{ delay: 0.3, type: "spring", stiffness: 200 }}
                  className="flex items-baseline gap-1"
                >
                  <span className="text-zinc-400 text-lg font-black">₹</span>
                  <span className="text-zinc-900 text-5xl font-black tracking-tight leading-none">{fare}</span>
                </motion.div>
              </div>
            </div>
          </motion.div>

          {/* ══ RIGHT — STATUS PANEL ══ */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.14, duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
            className="bg-white rounded-3xl border border-zinc-200 overflow-hidden shadow-[0_4px_24px_rgba(0,0,0,0.07)] flex flex-col"
          >
            <div className="h-1 bg-zinc-900" />

            <div className="flex-1 p-8 sm:p-10 flex flex-col">
              <AnimatePresence mode="wait">

                {/* ── IDLE ── */}
                {status === "idle" && (
                  <motion.div key="idle"
                    initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -12 }}
                    transition={{ duration: 0.3 }}
                    className="flex flex-col flex-1 justify-between"
                  >
                    <div>
                      <p className="text-[10px] font-black uppercase tracking-[0.18em] text-zinc-400 mb-1">Ready to go?</p>
                      <h3 className="text-2xl font-black text-zinc-900 mb-6">Confirm Your Ride</h3>
                      <div className="bg-zinc-50 border border-zinc-100 rounded-2xl p-5 space-y-3">
                        {[
                          { icon: <Clock size={14} />, text: "Driver will respond within 2 minutes" },
                          { icon: <ShieldCheck size={14} />, text: "Verified & insured drivers only" },
                          { icon: <CreditCard size={14} />, text: "Pay after driver accepts" },
                        ].map((item, i) => (
                          <div key={i} className="flex items-center gap-3">
                            <div className="w-7 h-7 rounded-xl bg-zinc-200 flex items-center justify-center text-zinc-600 flex-shrink-0">{item.icon}</div>
                            <p className="text-zinc-500 text-xs font-medium">{item.text}</p>
                          </div>
