                {/* ── AWAITING PAYMENT ── */}
                {status === "awaiting_payment" && (
                  <motion.div key="awaiting_payment"
                    initial={{ opacity: 0, scale: 0.94 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }}
