"use client";

import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import {
  IndianRupee,
  Loader2,
  Car,
  Bike,
  Truck,
  Calendar,
  ChevronRight,
  MapPin,
  User,
  Phone,
} from "lucide-react";

interface Booking {
  _id: string;
  pickupAddress: string;
  dropAddress: string;
  fare: number;
  status: string;
  paymentStatus: string;
  paymentMethod?: string;
  createdAt: string;
  user?: {
    name: string;
    phone?: string;
  };
  vehicle?: {
    vehicleModel: string;
    type?: string; // car, bike, auto, truck etc.
    imageUrl?: string;
    number?: string;
  };
  userMobileNumber?: string;
}

export default function PartnerBookingsPage() {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState("All");

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const res = await fetch("/api/partner/bookings");
        const data = await res.json();
        setBookings(data.bookings || []);
      } catch (err) {
        console.error("Failed to fetch bookings");
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, []);

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      confirmed: "bg-emerald-50 text-emerald-700 border-emerald-200",
      completed: "bg-teal-50 text-teal-700 border-teal-200",
      requested: "bg-amber-50 text-amber-700 border-amber-200",
      awaiting_payment: "bg-blue-50 text-blue-700 border-blue-200",
      cancelled: "bg-rose-50 text-rose-700 border-rose-200",
      rejected: "bg-red-50 text-red-700 border-red-200",
      expired: "bg-gray-50 text-gray-700 border-gray-200",
    };
    return colors[status] || "bg-gray-50 text-gray-700 border-gray-200";
  };

  const getVehicleIcon = (vehicleType?: string) => {
    switch(vehicleType?.toLowerCase()) {
      case 'bike':
      case 'motorcycle':
        return <Bike className="w-4 h-4 text-gray-400" />;
      case 'auto':
      case 'rickshaw':
        return <Car className="w-4 h-4 text-gray-400" />; // You can add Auto icon if available
      case 'truck':
      case 'lorry':
        return <Truck className="w-4 h-4 text-gray-400" />;
      case 'suv':
      case 'sedan':
      case 'hatchback':
      default:
        return <Car className="w-4 h-4 text-gray-400" />;
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      day: 'numeric',
      month: 'short',
      hour: '2-digit',
      minute: '2-digit'
    }).replace(',', '');
  };

  const filteredBookings = statusFilter === "All" 
    ? bookings 
    : bookings.filter(b => b.status === statusFilter.toLowerCase());

  return (
    <div className="min-h-screen bg-gray-50">
      
      {/* HEADER - PARTNER SPECIFIC */}
      <div className="bg-white border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="max-w-3xl mx-auto py-6">
            <div className="flex items-center gap-3">
              <div className="bg-blue-100 p-2 rounded-lg">
                <Car className="w-5 h-5 text-blue-600" />
              </div>
              <div>
                <h1 className="text-2xl font-semibold text-gray-900">Partner Bookings</h1>
                <p className="text-gray-500 text-sm mt-1">
                  {bookings.length} {bookings.length === 1 ? 'ride' : 'rides'} assigned to you
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* MAIN CONTENT */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <div className="max-w-3xl mx-auto">
          
          {/* FILTER BAR */}
          <div className="flex justify-between items-center mb-6">
            <div className="text-sm text-gray-500">
              Showing {filteredBookings.length} bookings
            </div>
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="bg-white border border-gray-200 rounded-lg px-3 py-1.5 text-sm text-gray-600 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option>All</option>
              <option>Confirmed</option>
              <option>Completed</option>
              <option>Requested</option>
              <option>Cancelled</option>
            </select>
          </div>

          {/* LOADING STATE */}
          {loading && (
            <div className="flex justify-center py-16">
              <Loader2 className="animate-spin w-8 h-8 text-blue-600" />
            </div>
          )}

          {/* EMPTY STATE */}
          {!loading && filteredBookings.length === 0 && (
            <div className="bg-white rounded-xl shadow-sm p-12 text-center">
              <Car className="w-12 h-12 text-gray-300 mx-auto mb-3" />
              <h3 className="text-lg font-medium text-gray-900">No bookings yet</h3>
              <p className="text-gray-500 text-sm mt-1">When customers book rides, they'll appear here</p>
            </div>
          )}

          {/* BOOKINGS LIST */}
          {!loading && filteredBookings.length > 0 && (
            <div className="space-y-4">
              {filteredBookings.map((booking, index) => (
                <motion.div
                  key={booking._id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                >
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all overflow-hidden">
                    
                    {/* CUSTOMER INFO - PARTNER SPECIFIC */}
                    <div className="flex items-center gap-3 p-4 bg-gradient-to-r from-blue-50 to-indigo-50 border-b border-gray-200">
                      {/* CUSTOMER AVATAR */}
                      <div className="w-12 h-12 rounded-full overflow-hidden bg-blue-200 flex-shrink-0 border-2 border-white shadow-sm flex items-center justify-center">
                        <User className="w-6 h-6 text-blue-600" />
                      </div>
                      
                      {/* CUSTOMER DETAILS */}
                      <div className="flex-1">
                        <div className="flex items-center justify-between">
                          <h3 className="font-semibold text-gray-900">
                            {booking.user?.name || "Customer"}
                          </h3>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(booking.status)}`}>
                            {booking.status.replace("_", " ")}
                          </span>
                        </div>
                        
                        {/* USER MOBILE NUMBER - UPDATED */}
                        {(booking.userMobileNumber || booking.user?.phone) && (
                          <div className="flex items-center gap-1 mt-1 text-xs text-gray-600">
                            <Phone className="w-3 h-3" />
                            <span>{booking.userMobileNumber || booking.user?.phone}</span>
                          </div>
                        )}
                      </div>
                    </div>

                    {/* VEHICLE INFO - WITH DYNAMIC ICON */}
                    {booking.vehicle && (
                      <div className="px-4 pt-3">
                        <div className="bg-gray-50 rounded-lg p-2 flex items-center gap-2">
                          {getVehicleIcon(booking.vehicle.type)}
                          <span className="text-xs text-gray-600">
                            {booking.vehicle.vehicleModel} • {booking.vehicle.number || "Not assigned"}
                          </span>
                        </div>
                      </div>
                    )}

                    {/* ADDRESS SECTION */}
                    <div className="p-4 space-y-3">
                      {/* PICKUP */}
                      <div className="flex items-start gap-3">
                        <div className="flex-shrink-0 w-6 h-6 bg-green-100 rounded-full flex items-center justify-center">
                          <MapPin className="w-3 h-3 text-green-600" />
                        </div>
                        <div className="flex-1">
                          <span className="text-xs font-medium text-green-600 uppercase tracking-wider">PICKUP</span>
                          <p className="text-sm text-gray-700 mt-0.5 leading-relaxed">
                            {booking.pickupAddress}
                          </p>
                        </div>
                      </div>

                      {/* DROP */}
                      <div className="flex items-start gap-3">
                        <div className="flex-shrink-0 w-6 h-6 bg-red-100 rounded-full flex items-center justify-center">
                          <MapPin className="w-3 h-3 text-red-600" />
                        </div>
                        <div className="flex-1">
                          <span className="text-xs font-medium text-red-600 uppercase tracking-wider">DROP</span>
                          <p className="text-sm text-gray-700 mt-0.5 leading-relaxed">
                            {booking.dropAddress}
                          </p>
                        </div>
                      </div>
                    </div>

                    {/* DATE AND FARE */}
                    <div className="flex items-center justify-between px-4 py-3 bg-gray-50 border-t border-gray-200">
                      <div className="flex items-center gap-2 text-sm text-gray-600">
                        <Calendar className="w-4 h-4 text-gray-400" />
                        <span>{formatDate(booking.createdAt)}</span>
                      </div>
                      <div className="flex items-center gap-1 font-semibold text-gray-900">
                        <IndianRupee className="w-4 h-4" />
                        <span>₹{booking.fare}</span>
                      </div>
                    </div>

                    {/* PAYMENT AND ACTIONS */}
                    <div className="flex items-center justify-between px-4 py-3 border-t border-gray-200">
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-500">Payment:</span>
                        <span className={`text-xs px-2 py-1 rounded-full ${
                          booking.paymentStatus === 'paid' 
                            ? 'bg-green-100 text-green-700' 
                            : 'bg-yellow-100 text-yellow-700'
                        }`}>
                          {booking.paymentStatus || 'pending'}
                        </span>
                        {booking.paymentMethod && (
                          <span className="text-xs text-gray-500 capitalize">
                            • {booking.paymentMethod}
                          </span>
                        )}
                      </div>

                      {booking.status!=="completed" &&  <div className="flex items-center gap-2">
                        {/* STATUS UPDATE BUTTONS - PARTNER SPECIFIC */}
                        
                        <button
                          onClick={() => window.location.href = `/partner/active-ride`}
                          className="flex items-center gap-1 text-sm font-medium text-blue-600 hover:text-blue-700 bg-blue-50 hover:bg-blue-100 px-4 py-1.5 rounded-lg transition-colors"
                        >
                          <span>Details</span>
                          <ChevronRight className="w-4 h-4" />
                        </button>
                      </div>}
                     
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import {
  ArrowLeft,
  CheckCircle,
  Landmark,
  CreditCard,
  BadgeCheck,
  Pencil,
  Phone,
} from "lucide-react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import axios from "axios";

/* ================= VALIDATION ================= */

const IFSC_REGEX = /^[A-Z]{4}0[A-Z0-9]{6}$/;

export default function PartnerBankPage() {
  const router = useRouter();

  const [name, setName] = useState("");
  const [account, setAccount] = useState("");
  const [ifsc, setIfsc] = useState("");
  const [upi, setUpi] = useState("");
  const [mobileNumber, setMobileNumber] = useState("");

  const [completed, setCompleted] = useState(false);
  const [editMode, setEditMode] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  /* ================= FETCH EXISTING BANK ================= */

  useEffect(() => {
    axios
      .get("/api/partner/bank")
      .then((res) => {
        if (res.data?.bank) {
          const bank = res.data.bank;
          setName(bank.accountHolderName || "");
          setIfsc(bank.ifsc || "");
          setAccount(bank.accountNumber || "" )
          setUpi(bank.upi || "");
          setMobileNumber(bank.mobileNumber || "");
          setCompleted(true);
        }
      })
      .catch(() => {});
  }, []);

  /* ================= VALIDATION ================= */

  const sanitizedIfsc = ifsc.trim().toUpperCase();

  const isNameValid = name.trim().length >= 3;
  const isAccountValid = account.trim().length >= 9;
  const isIfscValid =
    sanitizedIfsc.length === 11 &&
    IFSC_REGEX.test(sanitizedIfsc);
  const isMobileValid = mobileNumber.trim().length === 10;

  const canSubmit =
    isNameValid && isAccountValid && isIfscValid && isMobileValid;

  /* ================= SUBMIT ================= */

  const handleSubmit = async () => {
    if (completed && !editMode) {
      router.push("/");
      return;
    }

    try {
      setLoading(true);
      setError("");

      await axios.post("/api/partner/bank", {
        name: name.trim(),
        account,
        ifsc: sanitizedIfsc,
        upi: upi.trim() || undefined,
        mobileNumber: mobileNumber.trim(),
      });

      router.push("/");
    } catch (err: any) {
      setError(
        err?.response?.data?.message ||
          "Failed to save bank details"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-white flex items-center justify-center px-4">
      <motion.div
        initial={{ opacity: 0, y: 28 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-xl bg-white rounded-3xl border border-gray-200 shadow-[0_25px_70px_rgba(0,0,0,0.15)] p-6 sm:p-8"
      >
        {/* ================= HEADER ================= */}
        <div className="relative text-center">
          <button
            onClick={() => router.back()}
            className="absolute left-0 top-0 w-9 h-9 rounded-full border flex items-center justify-center hover:bg-gray-100 transition"
          >
            <ArrowLeft size={18} />
          </button>

          <p className="text-xs text-gray-500 font-medium">
            Step 3 of 3
          </p>

          <h1 className="text-2xl font-bold mt-1">
            Bank & Payout Setup
          </h1>

          <p className="text-sm text-gray-500 mt-2">
            Used for vendor payouts
          </p>

          {completed && !editMode && (
            <div className="mt-4 flex flex-col items-center gap-2">
              <div className="flex items-center gap-2 text-green-600 text-sm font-semibold">
                <CheckCircle size={16} />
                Bank details added
              </div>

              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setEditMode(true)}
                className="text-xs font-semibold underline flex items-center gap-1"
              >
                <Pencil size={12} />
                Edit details
              </motion.button>
            </div>
          )}
        </div>

        {/* ================= FORM ================= */}
        <div
          className={`mt-8 space-y-6 ${
            completed && !editMode
              ? "opacity-50 pointer-events-none"
              : ""
          }`}
        >
          <InputField
            label="Account holder name"
            placeholder="As per bank records"
            icon={<BadgeCheck size={16} />}
            value={name}
            onChange={setName}
            error={!isNameValid && name.length > 0}
            errorText="Minimum 3 characters required"
          />

          <InputField
            label="Bank account number"
            placeholder="Enter account number"
            icon={<CreditCard size={16} />}
            value={account}
            onChange={(v) =>
              setAccount(v.replace(/\D/g, ""))
            }
            error={!isAccountValid && account.length > 0}
            errorText="Account number must be at least 9 digits"
          />

          <InputField
            label="IFSC code"
            placeholder="HDFC0001234"
            icon={<Landmark size={16} />}
            value={ifsc}
            onChange={(v) =>
              setIfsc(v.replace(/\s/g, "").toUpperCase())
            }
            maxLength={11}
            error={ifsc.length === 11 && !isIfscValid}
            errorText="Invalid IFSC code"
          />

          <InputField
            label="Mobile number"
            placeholder="10 digit mobile number"
            icon={<Phone size={16} />}
            value={mobileNumber}
            onChange={(v) => setMobileNumber(v.replace(/\D/g, "").slice(0, 10))}
            maxLength={10}
            error={mobileNumber.length === 10 && !isMobileValid}
            errorText="Enter a valid 10-digit mobile number"
          />

          <InputField
            label="UPI ID (optional)"
            placeholder="name@upi"
            value={upi}
            onChange={setUpi}
            optional
          />
        </div>

        {/* ================= WHY DISABLED ================= */}
        {!canSubmit && editMode && (
          <div className="mt-6 text-xs text-gray-500 space-y-1">
            <p className="font-semibold">
              Complete the following to continue:
            </p>
            {!isNameValid && <p>• Valid account holder name</p>}
            {!isAccountValid && <p>• Valid bank account number</p>}
            {!isIfscValid && <p>• Correct IFSC code</p>}
            {!isMobileValid && <p>• Valid 10-digit mobile number</p>}
          </div>
        )}

        {/* ================= INFO ================= */}
        <div className="mt-6 flex items-start gap-3 text-xs text-gray-500">
          <CheckCircle size={16} className="mt-0.5" />
          <p>
            Bank details are verified before first payout.
            This usually takes 24–48 hours.
          </p>
        </div>

        {/* ================= ERROR ================= */}
        {error && (
          <p className="mt-4 text-sm text-red-500">
            {error}
          </p>
        )}

        {/* ================= CTA ================= */}
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.97 }}
          disabled={!canSubmit || loading}
          onClick={handleSubmit}
          className="mt-8 w-full h-14 rounded-2xl bg-black text-white font-semibold disabled:opacity-40 transition"
        >
          {completed && !editMode
            ? "Continue"
            : loading
            ? "Saving..."
            : "Save & Continue"}
        </motion.button>
      </motion.div>
    </div>
  );
}

/* ================= INPUT ================= */

function InputField({
  label,
  placeholder,
  value,
  onChange,
  icon,
  optional,
  maxLength,
  error,
  errorText,
}: {
  label: string;
  placeholder: string;
  value: string;
  onChange: (v: string) => void;
  icon?: React.ReactNode;
  optional?: boolean;
  maxLength?: number;
  error?: boolean;
  errorText?: string;
}) {
  return (
    <div>
      <label className="text-xs font-semibold text-gray-500">
        {label}{" "}
        {optional && (
          <span className="text-gray-400 font-normal">
            (optional)
          </span>
        )}
      </label>

      <div className="flex items-center gap-2 mt-2">
        {icon && <div className="text-gray-400">{icon}</div>}
        <input
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          maxLength={maxLength}
          className={`flex-1 border-b pb-2 text-sm focus:outline-none ${
            error
              ? "border-red-400 focus:border-red-500"
              : "border-gray-300 focus:border-black"
          }`}
        />
      </div>

      {error && errorText && (
        <p className="mt-1 text-xs text-red-500">
          {errorText}
        </p>
      )}
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import {
  ArrowLeft,
  ArrowRight,
  UploadCloud,
  FileCheck,
  CheckCircle,
  Pencil,
} from "lucide-react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import axios from "axios";

/* ================= TYPES ================= */

type DocKey = "aadhaar" | "license" | "rc";

/* ================= PAGE ================= */

export default function PartnerDocumentsPage() {
  const router = useRouter();

  const [docs, setDocs] = useState<Record<DocKey, File | null>>({
    aadhaar: null,
    license: null,
    rc: null,
  });

  const [completed, setCompleted] = useState(false);
  const [editMode, setEditMode] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  /* ================= FETCH EXISTING DOCS ================= */

  useEffect(() => {
    axios
      .get("/api/partner/documents")
      .then((res) => {
        if (res.data?.documents) {
          setCompleted(true);
        }
      })
      .catch(() => {});
  }, []);

  const canContinue =
    completed && !editMode
      ? true
      : docs.aadhaar && docs.license && docs.rc;

  const handleFileChange = (key: DocKey, file: File | null) => {
    if (!file) return;
    setDocs((prev) => ({ ...prev, [key]: file }));
  };

  /* ================= SUBMIT ================= */

  const submitDocuments = async () => {
    if (completed && !editMode) {
      router.push("/partner/onboard/bank");
      return;
    }

    if (!docs.aadhaar || !docs.license || !docs.rc) {
      setError("Please upload all required documents");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const formData = new FormData();
      formData.append("aadhaar", docs.aadhaar);
      formData.append("license", docs.license);
      formData.append("rc", docs.rc);

      await axios.post("/api/partner/documents", formData);

      router.push("/partner/onboard/bank");
    } catch (err: any) {
      setError(
        err?.response?.data?.message ||
          "Document upload failed"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-white flex items-center justify-center px-4">
      <motion.div
        initial={{ opacity: 0, y: 28 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
        className="w-full max-w-xl bg-white rounded-3xl border border-gray-200 shadow-[0_25px_70px_rgba(0,0,0,0.15)] p-6 sm:p-8"
      >
        {/* ================= HEADER ================= */}
        <div className="relative text-center">
          <button
            onClick={() => router.back()}
            className="absolute left-0 top-0 w-9 h-9 rounded-full border border-gray-300 flex items-center justify-center hover:bg-gray-100 transition"
          >
            <ArrowLeft size={18} />
          </button>

          <p className="text-xs text-gray-500 font-medium">
            Step 2 of 3
          </p>

          <h1 className="text-2xl font-bold mt-1">
            Upload Documents
          </h1>

          <p className="text-sm text-gray-500 mt-2">
            Required for verification
          </p>

          {completed && !editMode && (
            <div className="mt-4 flex flex-col items-center gap-2">
              <div className="flex items-center gap-2 text-green-600 text-sm font-semibold">
                <CheckCircle size={16} />
                Uploaded successfully
              </div>

              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setEditMode(true)}
                className="text-xs font-semibold text-black underline flex items-center gap-1"
              >
                <Pencil size={12} />
                Edit documents
              </motion.button>
            </div>
          )}
        </div>

        {/* ================= DOCUMENT LIST ================= */}
        <div
          className={`mt-8 space-y-5 ${
            completed && !editMode
              ? "opacity-50 pointer-events-none"
              : ""
          }`}
        >
          <DocUpload
            label="Aadhaar / ID Proof"
            desc="Government issued ID"
            file={docs.aadhaar}
            onChange={(f) =>
              handleFileChange("aadhaar", f)
            }
          />

          <DocUpload
            label="Driving License"
            desc="Valid driving license"
            file={docs.license}
            onChange={(f) =>
              handleFileChange("license", f)
            }
          />

          <DocUpload
            label="Vehicle RC"
            desc="Registration Certificate"
            file={docs.rc}
            onChange={(f) => handleFileChange("rc", f)}
          />
        </div>

        {/* INFO */}
        <div className="mt-6 flex items-start gap-3 text-xs text-gray-500">
          <FileCheck size={16} className="mt-0.5" />
          <p>
            Documents are securely stored and manually verified
            by our team.
          </p>
        </div>

        {/* ERROR */}
        {error && (
          <p className="mt-4 text-sm text-red-500">
            {error}
          </p>
        )}

        {/* CTA */}
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.97 }}
          disabled={loading}
          onClick={submitDocuments}
          className="mt-8 w-full h-14 rounded-2xl bg-black text-white font-semibold flex items-center justify-center gap-2 disabled:opacity-40 transition"
        >
          {completed && !editMode
            ? "Continue"
            : editMode
            ? "Save & Continue"
            : loading
            ? "Uploading..."
            : "Continue"}
          <ArrowRight size={18} />
        </motion.button>
      </motion.div>
    </div>
  );
}

/* ================= DOC UPLOAD ================= */

function DocUpload({
  label,
  desc,
  file,
  onChange,
}: {
  label: string;
  desc: string;
  file: File | null;
  onChange: (f: File | null) => void;
}) {
  return (
    <motion.label
      whileHover={{ scale: 1.02 }}
      className="flex items-center justify-between p-4 rounded-2xl border border-gray-200 cursor-pointer hover:border-black transition"
    >
      <div>
        <p className="text-sm font-semibold">
          {label}
        </p>
        <p className="text-xs text-gray-500">
          {desc}
        </p>
      </div>

      <div className="flex items-center gap-3">
        {file ? (
          <span className="text-xs text-green-600 font-medium">
            Selected
          </span>
        ) : (
          <span className="text-xs text-gray-400">
            Upload
          </span>
        )}

        <div className="w-10 h-10 rounded-full bg-black text-white flex items-center justify-center">
          <UploadCloud size={18} />
        </div>
      </div>

      <input
        type="file"
        accept="image/*,.pdf"
        hidden
        onChange={(e) =>
          onChange(e.target.files?.[0] || null)
        }
      />
    </motion.label>
  );
}

"use client";

import { motion } from "framer-motion";
import {
  ArrowLeft,
  ArrowRight,
  Bike,
  Car,
  Truck,
  Package,
  CheckCircle,
  Pencil,
} from "lucide-react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import axios from "axios";
import { useSession } from "next-auth/react";

/* ================= CONFIG ================= */

type VehicleId = "bike" | "auto" | "car" | "loading" | "truck";

const VEHICLES = [
  { id: "bike", label: "Bike", icon: Bike, desc: "2 wheeler" },
  { id: "auto", label: "Auto", icon: Car, desc: "3 wheeler ride" },
  { id: "car", label: "Car", icon: Car, desc: "4 wheeler ride" },
  { id: "loading", label: "Loading", icon: Package, desc: "Small goods" },
  { id: "truck", label: "Truck", icon: Truck, desc: "Heavy transport" },
];

const VEHICLE_REGEX =
  /^[A-Z]{2}[0-9]{1,2}[A-Z]{0,2}[0-9]{4}$/;

/* ================= PAGE ================= */

export default function PartnerVehiclePage() {
  const router = useRouter();
  const { update } = useSession();

  const [vehicleType, setVehicleType] = useState<string>("");
  const [vehicleNumber, setVehicleNumber] = useState("");
  const [vehicleModel, setVehicleModel] = useState("");

  const [completed, setCompleted] = useState(false);
  const [editMode, setEditMode] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  /* ================= FETCH VEHICLE (AUTO-FILL) ================= */

  useEffect(() => {
    async function load() {
      try {
        const res = await axios.get("/api/partner/vehicle");

        const { user, vehicle } = res.data;

        if (user?.vendorOnboardingStep >= 1) {
          setCompleted(true);
        }

        // 🔥 AUTO FILL FROM API
        if (vehicle) {
          setVehicleType(vehicle.type);
          setVehicleNumber(vehicle.number);
          setVehicleModel(vehicle.model);
        }
      } catch (err) {
        console.error("Vehicle fetch failed");
      }
    }

    load();
  }, []);

  /* ================= SUBMIT ================= */

  const submitVehicle = async () => {
    if (completed && !editMode) {
      router.push("/partner/onboard/documents");
      return;
    }

    if (!vehicleType) {
      setError("Select vehicle type");
      return;
    }

    if (!VEHICLE_REGEX.test(vehicleNumber)) {
      setError("Invalid vehicle number (e.g. MH12AB1234)");
      return;
    }

    if (vehicleModel.trim().length < 3) {
      setError("Invalid vehicle model");
      return;
    }

    setError(null);
    setLoading(true);

    try {
      await axios.post("/api/partner/vehicle", {
        type: vehicleType,
        number: vehicleNumber,
        vehicleModel,
      });

      await update({ role: "vendor" });

      router.push("/partner/onboard/documents");
    } catch (err: any) {
      setError(err?.response?.data?.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-white flex items-center justify-center px-4">
      <motion.div
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
        className="w-full max-w-xl bg-white rounded-3xl border border-gray-200 shadow-[0_25px_70px_rgba(0,0,0,0.15)] p-6 sm:p-8"
      >
        {/* ================= HEADER ================= */}
        <div className="relative text-center">
          <button
            onClick={() => router.back()}
            className="absolute left-0 top-0 w-9 h-9 rounded-full border border-gray-300 flex items-center justify-center hover:bg-gray-100 transition"
          >
            <ArrowLeft size={18} />
          </button>

          <p className="text-xs text-gray-500 font-medium">
            Step 1 of 3
          </p>

          <h1 className="text-2xl font-bold mt-1">
            Vehicle Details
          </h1>

          <p className="text-sm text-gray-500 mt-2">
            Add your vehicle information
          </p>

          {completed && !editMode && (
            <div className="mt-4 flex flex-col items-center gap-2">
              <div className="flex items-center gap-2 text-green-600 text-sm font-semibold">
                <CheckCircle size={16} />
                Completed
              </div>

              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setEditMode(true)}
                className="text-xs font-semibold text-black underline flex items-center gap-1"
              >
                <Pencil size={12} />
                Edit details
              </motion.button>
            </div>
          )}
        </div>

        {/* ================= FORM ================= */}
        <div
          className={`mt-8 space-y-6 ${
            completed && !editMode
              ? "opacity-50 pointer-events-none"
              : ""
          }`}
        >
          {/* VEHICLE TYPE */}
          <div>
            <p className="text-xs font-semibold text-gray-500 mb-3">
              Vehicle type
            </p>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
              {VEHICLES.map((v) => {
                const Icon = v.icon;
                const active = vehicleType === v.id;

                return (
                  <motion.button
                    key={v.id}
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.96 }}
                    onClick={() => setVehicleType(v.id)}
                    className={`rounded-2xl border p-4 flex flex-col items-center gap-2 transition
                      ${
                        active
                          ? "bg-black text-white border-black"
                          : "border-gray-200 hover:border-black"
                      }`}
                  >
                    <div
                      className={`w-11 h-11 rounded-full flex items-center justify-center
                        ${
                          active
                            ? "bg-white text-black"
                            : "bg-black text-white"
                        }`}
                    >
                      <Icon size={20} />
                    </div>

                    <p className="text-sm font-semibold">
                      {v.label}
                    </p>

                    <p
                      className={`text-xs ${
                        active
                          ? "text-gray-300"
                          : "text-gray-500"
                      }`}
                    >
                      {v.desc}
                    </p>
                  </motion.button>
                );
              })}
            </div>
          </div>

          {/* VEHICLE NUMBER */}
          <div>
            <label className="text-xs font-semibold text-gray-500">
              Vehicle number
            </label>
            <input
              value={vehicleNumber}
              onChange={(e) =>
                setVehicleNumber(e.target.value.toUpperCase())
              }
              placeholder="MH12AB1234"
              className="mt-2 w-full border-b border-gray-300 pb-2 text-sm focus:outline-none focus:border-black transition"
            />
          </div>

          {/* VEHICLE MODEL */}
          <div>
            <label className="text-xs font-semibold text-gray-500">
              Vehicle model / capacity
            </label>
            <input
              value={vehicleModel}
              onChange={(e) => setVehicleModel(e.target.value)}
              placeholder="Tata Ace / 1.5 Ton"
              className="mt-2 w-full border-b border-gray-300 pb-2 text-sm focus:outline-none focus:border-black transition"
            />
          </div>
        </div>

        {/* ERROR */}
        {error && (
          <p className="mt-4 text-sm text-red-500">
            {error}
          </p>
        )}

        {/* CTA */}
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.97 }}
          disabled={loading}
          onClick={submitVehicle}
          className="mt-8 w-full h-14 rounded-2xl bg-black text-white font-semibold flex items-center justify-center gap-2 disabled:opacity-40 transition"
        >
          {completed && !editMode
            ? "Continue"
            : editMode
            ? "Save & Continue"
            : loading
            ? "Submitting..."
            : "Continue"}
          <ArrowRight size={18} />
        </motion.button>
      </motion.div>
    </div>
  );
}

"use client";

import dynamic from "next/dynamic";
import {
  Phone, Car, User2, ChevronUp,
